"""HLD Advanced Topics: Data Structures for Big Data, Vector Databases, Time Series Databases — 20 MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def bigdata_ds_lesson() -> Lesson:
    return Lesson(id="hld-bigdata-ds", number=125, title="Data Structures for Big Data",
        focus=("Bloom filter","HyperLogLog","Count-Min Sketch","skip list","trie","geohash"),
        overview="Probabilistic and space-efficient data structures that solve massive-scale problems elegantly.",
        patterns=(), badge="HLD Advanced", tasks=(
        quiz("bd-1","What is a Bloom filter?","hard",("big-data",),("A probabilistic structure: may say 'possibly yes' but never 'definitely no' — false positives, no false negatives","A security protocol that authenticates both client and server during the handshake","A replication strategy where writes go to any node and conflicts are resolved on read","A sharding approach that distributes cached entries across nodes by consistent hashing"),0,"Space-efficient membership test. Used for cache penetration prevention, spam filtering, spell checking."),
        quiz("bd-2","What is a HyperLogLog?","hard",("big-data",),("A probabilistic algorithm for cardinality estimation (count distinct) using O(1) space with ~2% error","A replication technique that mirrors hot cache entries across multiple nodes for availability","A resilience pattern that isolates failures in one subsystem from propagating to others","A DNS-based technique that distributes queries across multiple authoritative servers"),0,"Count 1 billion unique visitors with only 12KB. Redis PFADD/PFCOUNT implements this."),
        quiz("bd-3","What is a Count-Min Sketch?","hard",("big-data",),("A probabilistic frequency table: estimates how many times an element has been seen, with possible overcount","A partitioning strategy that splits data based on a hash of the composite primary key","A deployment strategy that gradually shifts traffic from the old version to the new one","A communication pattern where services exchange messages through a centralized broker"),0,"CMS: O(1) space per element. Used for heavy hitters, top-K queries, and frequency estimation."),
        quiz("bd-4","What is a skip list?","hard",("big-data",),("A layered sorted linked list providing O(log n) search, insert, delete — used by Redis Sorted Sets","A pattern where incoming requests are buffered and processed in priority-ordered batches","A warming strategy that pre-loads data based on access frequency from the previous day","A scheduling algorithm that assigns tasks to workers based on estimated completion time"),0,"Skip lists: probabilistic balancing without tree rotations. Simpler to implement than balanced BSTs."),
        quiz("bd-5","What is a trie (prefix tree)?","medium",("big-data",),("A tree where each edge represents a character — O(k) lookup for k-length strings. Used for autocomplete","A monitoring approach that aggregates metrics from multiple sources into unified dashboards","A serialization format that reduces cache entry size through schema-aware compression","A persistence mechanism that snapshots the cache state to disk for crash recovery"),0,"Tries: prefix-based search, autocomplete, IP routing tables. Space-efficient for shared prefixes."),
        quiz("bd-6","What is a geohash?","hard",("big-data",),("Encodes 2D lat/lng into a 1D string by interleaving bits — nearby points share prefixes for range queries","A connection management approach that limits concurrent sessions to prevent overload","A protocol that batches multiple requests into a single TCP segment for efficiency","A flow control mechanism that prevents the sender from overwhelming the receiver"),0,"Geohash 'gc7x' means NYC area. Longer string = more precision. Used for proximity search."),
        quiz("bd-7","What is a Merkle tree?","hard",("big-data",),("A hash tree where each leaf is a hash of data and each node is a hash of its children — detects differences efficiently","A replication technique that synchronously mirrors writes to a standby for zero data loss","A schema design pattern that embeds frequently accessed data to avoid join overhead","A process that periodically reconciles state between systems to detect and fix drift"),0,"Merkle trees: compare two datasets by comparing root hashes. Used in Git, blockchain, Cassandra repair."),
        quiz("bd-8","What is a T-digest?","hard",("big-data",),("An algorithm for accurate estimation of quantiles (p50, p99) from streaming data with bounded memory","A connection management approach that pins clients to specific backend instances","A coordination service that uses ephemeral nodes for automatic failure detection","A technique where the server pre-fetches resources based on predicted client needs"),0,"T-digest: compute accurate percentiles over billions of data points with only kilobytes of state."),
        quiz("bd-9","What is a quotient filter?","hard",("big-data",),("A space-efficient probabilistic data structure for set membership, supporting deletion (unlike Bloom filters)","A prefetching algorithm that predicts future access patterns from recent query history","A load shedding strategy that drops low-priority requests when resource utilization is high","A technique that partitions workload across worker pools based on resource requirements"),0,"Quotient filters: similar to Bloom but support deletion and have better cache performance."),
        quiz("bd-10","What is a Cuckoo filter?","hard",("big-data",),("A probabilistic data structure supporting membership testing AND deletion with better space efficiency than Bloom","A consensus protocol that uses a rotating leader to distribute write coordination load","A transaction isolation level that prevents phantom reads using predicate locking","A consistency model where reads from any replica are guaranteed to be monotonically fresh"),0,"Cuckoo filters: 2 hash functions, elements can be relocated. Supports delete. Often better than Bloom in practice."),
        quiz("bd-11","What is an R-tree?","hard",("big-data",),("A spatial index for multi-dimensional data (bounding rectangles) — used for geographic range queries","An index maintenance operation that rebuilds fragmented pages for better scan performance","A membership protocol where nodes periodically exchange state with random cluster peers","A clock synchronization technique that uses NTP with bounded drift for ordering events"),0,"R-trees: used by PostGIS for spatial queries like 'find all restaurants within this bounding box'."),
        quiz("bd-12","What is a roaring bitmap?","hard",("big-data",),("A compressed bitmap using a hybrid of arrays, bitmaps, and run-length encoding for efficient set operations","A cache coherence protocol that broadcasts invalidation messages to all cache tiers","A transport layer optimization that reduces round-trip overhead using multiplexing","A data structure that stores cache metadata compactly using probabilistic counting"),0,"Roaring bitmaps: much more space-efficient than plain bitmaps. Used in Elasticsearch, Apache Druid."),
        quiz("bd-13","What is consistent hashing with bounded loads?","hard",("big-data",),("Variant where each node has a max load cap — overflow keys spill to next node, preventing hotspots","Standard consistent hashing across multiple service instances","A routing strategy that directs traffic based on geographic proximity of the client","A partitioning algorithm that assigns data based on a hash of the geographic region"),0,"Bounded load: Google's algorithm ensures no node exceeds (1+ε) × average load."),
        quiz("bd-14","What is a DAWG (Directed Acyclic Word Graph)?","hard",("big-data",),("A trie that shares suffixes too (not just prefixes) — more compact for dictionary storage","An eviction algorithm that considers both recency and frequency when selecting victims","A backup mechanism that captures incremental changes since the last full snapshot","A monitoring tool that tracks query execution plans and identifies slow running queries"),0,"DAWG: minimal automaton for a set of strings. More compact than trie. Used in spell checkers."),
        quiz("bd-15","What is SimHash?","hard",("big-data",),("A locality-sensitive hash: similar documents produce similar hashes — used for near-duplicate detection","A data pipeline stage that transforms and enriches events before writing to storage","A storage engine optimization that pre-sorts data on disk for sequential access patterns","A monitoring tool that tracks hit rates, eviction counts, and memory usage per cache pool"),0,"SimHash: detect duplicate web pages, similar articles, or plagiarism at web scale."),
        quiz("bd-16","What is a ring buffer?","medium",("big-data",),("A fixed-size circular buffer where new data overwrites oldest — used for recent events, metrics, logs","A testing approach that injects controlled failures to verify system recovery behavior","A state synchronization approach that reconciles differences using Merkle tree comparison","A query optimization strategy that rewrites subqueries into more efficient join patterns"),0,"Ring buffers: bounded memory, O(1) insert, natural sliding window. Used in Disruptor, kernel networking."),
        quiz("bd-17","What is the MinHash algorithm?","hard",("big-data",),("Estimates Jaccard similarity between sets using random hash functions — used for near-duplicate detection at scale","A mechanism that compresses HTTP headers to reduce bandwidth on repeated requests","A failure detection mechanism using heartbeat intervals and configurable timeout thresholds","A congestion avoidance algorithm that dynamically adjusts the transmission window"),0,"MinHash: compute approximate set similarity without comparing full sets. O(k) per comparison."),
        quiz("bd-18","What is a segment tree?","hard",("big-data",),("A tree for efficient range queries (sum, min, max) with O(log n) update and query on intervals","A self-balancing B-tree variant optimized for storing database index records","A cryptographic hash function designed to verify file chunk transfers","A doubly linked list structure used to cache recent query values"),0,"Segment trees: used in competitive programming and databases for range aggregation queries."),
        quiz("bd-19","What is a Fenwick tree (Binary Indexed Tree)?","hard",("big-data",),("A tree for efficient prefix sum queries and point updates in O(log n) — simpler than segment trees","A sequential linked list structure optimized for fast node insertions","A cryptographic hash function used to build Merkle block roots","A self-balancing B-tree used to index document search keywords"),0,"Fenwick trees: compact representation for cumulative frequency tables. Less memory than segment trees."),
        quiz("bd-20","What is the difference between exact and approximate algorithms for big data?","medium",("big-data",),("Exact algorithms use O(n) space; approximate use O(1) or O(log n) with bounded error — tradeoff accuracy for scalability","Exact algorithms are always faster since they bypass probabilistic estimation cycles","Approximate algorithms are always incorrect and trigger automatic node failover","They are identical in memory usage, differing only in query complexity"),0,"At scale, exact cardinality (hash set) is impossible. HyperLogLog: 12KB vs 1GB for exact, ~2% error."),
    ))

def vector_db_lesson() -> Lesson:
    return Lesson(id="hld-vector-db", number=126, title="Vector Databases",
        focus=("embeddings","ANN search","HNSW","IVF","similarity metrics","RAG"),
        overview="Vector databases power AI search, recommendations, and RAG. Know embedding storage and ANN algorithms.",
        patterns=(), badge="HLD Advanced", tasks=(
        quiz("vec-1","What is a vector database?","medium",("vector-db",),("A database optimized for storing, indexing, and querying high-dimensional vectors (embeddings)","A relational database configured to index tables via foreign keys","A memory-cached key-value store optimized for transaction logs","A network graph database representing connection nodes and edges"),0,"Vector DBs (Pinecone, Weaviate, Milvus, Qdrant) support similarity search on embeddings."),
        quiz("vec-2","What is an embedding?","medium",("vector-db",),("A dense numerical vector representing the semantic meaning of text, images, or other data","A parsing token representing a single vocabulary word in text","A signed URL used to securely download media files from storage","A cryptographic hash value generated by index compression routines"),0,"Embeddings: 'cat' → [0.2, 0.8, ...]. Similar concepts have similar vectors (close in space)."),
        quiz("vec-3","What is approximate nearest neighbor (ANN) search?","hard",("vector-db",),("Finding vectors close to a query vector in high-dimensional space, sacrificing some accuracy for speed","An exact search mode that scans all vectors using brute force distance","A cryptographic hash function used to bucket database primary keys","A sorting algorithm that orders numerical query results in memory"),0,"Exact KNN is O(n). ANN is ~O(log n) with >95% recall. Essential for real-time vector search."),
        quiz("vec-4","What is HNSW (Hierarchical Navigable Small World)?","hard",("vector-db",),("A graph-based ANN algorithm with multiple layers — fast, high recall, used by most vector DBs","A self-balancing B-tree variant optimized for range query index paths","A locality-sensitive hash function that buckets vectors into clusters","A virtual database index that caches query records client-side"),0,"HNSW: navigate from coarse top layer to fine bottom layer. O(log n) search. Best quality/speed tradeoff."),
        quiz("vec-5","What is IVF (Inverted File Index) for vectors?","hard",("vector-db",),("Clusters vectors into partitions; search only the nearest clusters instead of all vectors","A full-text index containing searchable document text keywords","A memory-mapped key-value hash table for transaction caches","A distributed B-tree index configured to split keys across nodes"),0,"IVF: K-means clustering → search only top-k clusters. Fast but needs periodic re-clustering."),
        quiz("vec-6","What is the difference between cosine similarity and Euclidean distance?","hard",("vector-db",),("Cosine measures angle (direction); Euclidean measures straight-line distance (magnitude matters)","They are identical similarity metrics, named differently based on model types","Euclidean distance is superior for all model embeddings and prevents failover","Cosine similarity is computationally simpler and executes faster than distance"),0,"Cosine similarity: good for text (direction matters). Euclidean: good when magnitude is meaningful."),
        quiz("vec-7","What is RAG (Retrieval Augmented Generation)?","medium",("vector-db",),("Retrieve relevant documents via vector search, then feed them as context to an LLM for grounded answers","A specialized database type optimized for real-time model updates","A fine-tuning optimization method that modifies neural network weights","An unsupervised training technique used to create large vocabulary models"),0,"RAG: embed docs → store in vector DB → query → retrieve top-K → inject into LLM prompt → generate answer."),
        quiz("vec-8","What is the curse of dimensionality?","hard",("vector-db",),("In high dimensions, all points become roughly equidistant, making exact distance measures less meaningful","A storage disk bottleneck caused by storing large vector arrays","A coding exception that occurs when vector models change shapes","A network connection latency bottleneck during cluster routing"),0,"At 1000+ dimensions, distance becomes less discriminative. Dimensionality reduction (PCA) can help."),
        quiz("vec-9","What is product quantization?","hard",("vector-db",),("A compression technique: split vectors into sub-vectors, quantize each independently, reducing storage and compute","A database index configuration used to partition primary keys","A vector multiplication operation used to calculate distances","A cryptographic hashing function that maps keys to memory buckets"),0,"PQ: 768-dim vector → 96 sub-vectors of 8 dims each → 96 bytes instead of 3072. Approximate but fast."),
        quiz("vec-10","What is the difference between Pinecone and Milvus?","hard",("vector-db",),("Pinecone: fully managed cloud service. Milvus: open-source, self-hosted, more customizable","Pinecone is a self-hosted open-source vector index system","Milvus is a cloud-only fully managed SaaS vector database","They are identical vector indexes developed by the same vendor"),0,"Pinecone: zero-ops. Milvus: full control, GPU acceleration, multiple index types."),
        quiz("vec-11","What is hybrid search in vector databases?","hard",("vector-db",),("Combining vector similarity search with traditional keyword/filter search for better results","A replication strategy that mirrors vectors across regional nodes","A design that queries a relational database and a vector database sequentially","A partitioning scheme that splits vector indexes based on creation dates"),0,"Hybrid: vector search for semantic relevance + keyword filters (category, date) for precision."),
        quiz("vec-12","What is the role of metadata filtering in vector search?","medium",("vector-db",),("Pre-filter or post-filter vectors by metadata (tags, categories, dates) before/after similarity computation","Metadata filtering has no effect on vector query results","A cache optimization strategy that pre-loads hot index queries","An index partitioning rule configured during database boot"),0,"Pre-filtering: narrow candidates first, then vector search. More efficient for selective queries."),
        quiz("vec-13","What is the embedding dimension tradeoff?","hard",("vector-db",),("Higher dimensions capture more nuance but use more storage, slower search, and need more training data","Dimension counts have no impact on database indexing performance","Higher dimensions are universally superior and require less memory","Lower dimensions capture more details and search slower than high ones"),0,"OpenAI ada-002: 1536 dims. MiniLM: 384 dims. Smaller models are faster but less expressive."),
        quiz("vec-14","How do you update vectors in a vector database?","medium",("vector-db",),("Delete and re-insert: most vector indexes (HNSW, IVF) don't support efficient in-place updates","Executing a standard SQL UPDATE command on the index tables","Performing an in-place modification of individual vector elements","Modifying index structures directly in memory without re-inserting"),0,"Vector DBs often use a delete+insert pattern. Some support upsert for convenience."),
        quiz("vec-15","What is the distance metric inner product?","hard",("vector-db",),("Dot product of two vectors — equivalent to cosine similarity when vectors are normalized","A locality-sensitive hash function that divides vector spaces","A multi-dimensional Euclidean distance calculation algorithm","A synonym for cosine similarity regardless of vector normalization"),0,"For normalized vectors: inner product = cosine similarity. Many models pre-normalize embeddings."),
        quiz("vec-16","What is the ScaNN algorithm?","hard",("vector-db",),("Google's ANN algorithm using learned quantization and asymmetric hashing for state-of-the-art speed/recall","A standalone vector database engine optimized for spatial data","A locality-sensitive hashing function that buckets text files","A self-balancing B-tree index that sorts document keyword strings"),0,"ScaNN: anisotropic vector quantization. Among the fastest ANN algorithms. Used in Google Search."),
        quiz("vec-17","How do vector databases handle scale?","hard",("vector-db",),("Sharding vectors across nodes + replicas for read scaling + in-memory indexes with disk spillover","Running all vector search indexes on a single high-performance mainframe","Allowing index sizes to grow indefinitely without cluster partitioning","Upgrading server memory capacity without using replication folders"),0,"Shard by ID or by vector cluster. Scatter-gather for cross-shard queries. Replicas for read throughput."),
        quiz("vec-18","What is the re-ranking pattern in vector search?","hard",("vector-db",),("Retrieve top-K candidates with fast ANN, then re-rank with a more expensive cross-encoder model for precision","Sorting the database search output chronologically by creation timestamp","A memory cache replacement policy that updates hot index keys","A database partitioning rule that maps vectors to storage shards"),0,"Two-stage: fast retrieval (bi-encoder + ANN) → precise re-ranking (cross-encoder). Balances speed and quality."),
        quiz("vec-19","What is the embedding update challenge?","hard",("vector-db",),("When the embedding model changes, ALL vectors must be re-computed and re-indexed — expensive at scale","There are no operational challenges associated with updating indexes","Embedding values are fixed in database schemas and cannot be updated","The database automatically updates vector coordinates using background ML"),0,"Model upgrade: re-embed entire corpus. Versioned indexes or gradual migration needed."),
        quiz("vec-20","What is multi-modal search with vector databases?","hard",("vector-db",),("Searching across different data types (text, images, audio) using a shared embedding space (CLIP, etc.)","Executing separate text searches across multiple database schemas","A database configuration that allows multiple simultaneous query connections","A cache routing optimization that distributes files globally"),0,"CLIP embeds images and text into the same vector space. Search images with text queries and vice versa."),
    ))

def timeseries_db_lesson() -> Lesson:
    return Lesson(id="hld-timeseries-db", number=127, title="Time Series Databases",
        focus=("InfluxDB","TimescaleDB","Prometheus","downsampling","retention","compression"),
        overview="Time-series databases handle metrics, IoT, and financial data at massive scale. Know their internals.",
        patterns=(), badge="HLD Advanced", tasks=(
        quiz("ts-1","What is a time-series database optimized for?","medium",("timeseries",),("Append-heavy workloads with timestamp-ordered data: metrics, IoT, financial, and event data","Storing and querying normalized user profiles and account records","Full-text search indexing and query relevance optimization","Recursive graph network traversal and relationship mappings"),0,"TSDB: optimized for high write throughput, time-range queries, and automatic data retention."),
        quiz("ts-2","What is the difference between InfluxDB and TimescaleDB?","hard",("timeseries",),("InfluxDB: custom engine, Flux query language. TimescaleDB: PostgreSQL extension, uses SQL","TimescaleDB is a standalone custom database that does not run on PostgreSQL","InfluxDB is a PostgreSQL extension that uses standard SQL queries","They are identical database engines distributed under different brand names"),0,"TimescaleDB: full PostgreSQL compatibility + time-series optimizations. InfluxDB: purpose-built, custom query."),
        quiz("ts-3","What is downsampling in time-series?","medium",("timeseries",),("Aggregating high-resolution data into lower-resolution summaries (1-second → 1-minute averages)","Compressing database log files on disk using binary delta compression","Reducing query result resolution by filtering out anomalous readings","Deleting historical database rows once they exceed a set age limit"),0,"Keep 1s resolution for 24h, 1m for 30d, 1h for 1y. Reduces storage while preserving trends."),
        quiz("ts-4","What is data retention policy?","medium",("timeseries",),("Automatically deleting data older than a threshold to manage storage costs","A backup schedule that copies database snapshots to remote storage","A replication rule that mirrors time-series data to other zones","A configuration that guarantees historical records are never deleted"),0,"Retention: keep raw data for 30d, downsampled for 1y, delete after. Automates lifecycle management."),
        quiz("ts-5","What is Prometheus and what is it used for?","medium",("timeseries",),("A monitoring and alerting toolkit that collects metrics via pull model and stores as time-series","A NoSQL relational database optimized for analytics query paths","A high-throughput message queue used to buffer telemetry events","An in-memory cache layer placed in front of primary databases"),0,"Prometheus: scrapes /metrics endpoints, stores time-series, evaluates alert rules, integrates with Grafana."),
        quiz("ts-6","What is the pull vs push model for metrics collection?","hard",("timeseries",),("Pull (Prometheus): server scrapes targets. Push (Graphite, InfluxDB): targets send metrics to server","They are identical concepts, differing only in client socket library choice","The pull model is universally superior for all network topologies","The push model is universally superior since it eliminates server lag"),0,"Pull: easier service discovery, no metric loss on target crash. Push: better for short-lived jobs, firewalled envs."),
        quiz("ts-7","What is columnar storage and why does it matter for time-series?","hard",("timeseries",),("Storing data column-by-column enables better compression and faster aggregation queries","A cache buffer layout that separates read and write operations","A standard row-oriented table partition stored in flat text files","They are identical storage styles; the name differs by database vendor"),0,"Columnar: compress timestamps together (delta encoding), values together (gorilla compression). 10-100x smaller."),
        quiz("ts-8","What is Gorilla compression for time-series?","hard",("timeseries",),("Facebook's compression for timestamps (delta-of-delta) and values (XOR) — ~12 bytes per data point to ~1.37 bytes","A standard ZIP compression utility applied to raw database folders","A hash-based indexing optimization that buckets metric events","A sorting algorithm that orders data points chronologically on insert"),0,"Gorilla: timestamps compress via delta-of-delta. Float values compress via XOR with previous. Massive savings."),
        quiz("ts-9","What is a time-series tag/label?","medium",("timeseries",),("Metadata key-value pairs identifying a metric series (host=server1, region=us-east, metric=cpu_usage)","A data category folder used to organize metric files on disk","The actual numerical value payload of the metric measurement","The timestamp indicating when the metric was recorded by the client"),0,"Tags define the cardinality of time-series. High-cardinality tags (user_id) can explode storage."),
        quiz("ts-10","What is the cardinality problem in time-series?","hard",("timeseries",),("Too many unique tag combinations create too many series, overwhelming storage and index","A network collision bottleneck caused by simultaneous metric transmissions","Having too many numerical metric values stored in a single table","An error that occurs when too few metrics are submitted to the server"),0,"1000 hosts × 100 metrics × 10 regions = 1M series. Each series has its own index entry. Cardinality explosion."),
        quiz("ts-11","What is a chunk/block in time-series storage?","hard",("timeseries",),("A fixed time window of data compressed and stored as a single unit (e.g., 2-hour Prometheus block)","A single row in a relational database containing metric fields","A geographical partition folder used to mirror tables globally","A temporary cache entry stored in the memory gateway buffer"),0,"Chunks: immutable compressed blocks. Active chunk in memory, older chunks on disk. Append-only within chunk."),
        quiz("ts-12","What is the difference between metric and event time-series?","medium",("timeseries",),("Metrics: regular interval readings (CPU every 10s). Events: irregular occurrences (login, error, purchase)","Events are submitted at fixed intervals; metrics are irregular","They are synonyms for the same stream data structure type","Metrics are a subtype of events that must be parsed by compilers"),0,"Metrics: fixed rate, predictable. Events: variable rate, unpredictable. Different storage optimizations."),
        quiz("ts-13","What is PromQL?","hard",("timeseries",),("Prometheus Query Language: rate(), histogram_quantile(), aggregation by labels for monitoring queries","A standalone database engine optimized for spatial telemetry","A REST API protocol used to transmit metrics from clients","A standard dialect of SQL used to query time-series databases"),0,"PromQL: rate(http_requests_total[5m]): per-second request rate over 5 minutes. Powerful for monitoring."),
        quiz("ts-14","What is a recording rule in Prometheus?","hard",("timeseries",),("Pre-compute expensive PromQL queries and save results as new time-series — improves dashboard performance","A replication setting that mirrors metrics across remote servers","A backup configuration that schedules database snapshot writes","A data retention rule that deletes old metrics from memory"),0,"Recording rules: compute once, store result. Dashboards read the pre-computed series instead of re-computing."),
        quiz("ts-15","What is the WAL in time-series databases?","hard",("timeseries",),("Write-Ahead Log ensures recent data survives crashes — data is buffered in WAL before compaction into blocks","A backup recovery configuration that copies files to S3","A specialized index structure optimized for timestamp columns","A query planner optimization that runs queries in parallel"),0,"WAL: crash recovery for the current active block. On restart, replay WAL to rebuild in-memory state."),
        quiz("ts-16","What is a continuous aggregate in TimescaleDB?","hard",("timeseries",),("An automatically maintained materialized view that incrementally aggregates new data as it arrives","A replication setting that distributes aggregates across shards","An in-memory cache block that stores popular query outputs","A standard SQL view query that does not cache or store computed data"),0,"Continuous aggregates: real-time materialized views. New data auto-aggregated without full recompute."),
        quiz("ts-17","What is the difference between Prometheus and Thanos/Cortex?","hard",("timeseries",),("Thanos/Cortex add long-term storage, global query view, and horizontal scaling on top of Prometheus","They are identical monitoring systems distributed by the same company","Cortex is a legacy monitoring tool that has been replaced by Prometheus","Thanos is a direct competitor that replaces Prometheus database engines"),0,"Prometheus: single instance. Thanos: object storage backend, cross-cluster queries, unlimited retention."),
        quiz("ts-18","How does QuestDB achieve high write throughput?","hard",("timeseries",),("Memory-mapped files, column-oriented storage, SIMD instructions, and zero-copy ingestion","Running a standard PostgreSQL engine with minor buffer enhancements","Using a single-threaded architecture that avoids lock context switches","Storing all metric tables exclusively in memory without disk persistence"),0,"QuestDB: millions of rows/sec ingestion. Uses SIMD for vectorized operations on time-series data."),
        quiz("ts-19","What is the exemplar feature in Prometheus?","hard",("timeseries",),("Links a metric data point to a specific trace ID, bridging metrics and distributed tracing","A representative metric data point used for target calibrations","A custom label tag applied to distinguish metric sources","A pre-computed recording rule used to speed up dashboard charts"),0,"Exemplars: click on a latency spike → see the exact trace that caused it. Metrics → traces correlation."),
        quiz("ts-20","When should you NOT use a time-series database?","medium",("timeseries",),("For non-time-ordered data, complex JOINs, transactions, or general-purpose application data","When the metric database size exceeds one terabyte of storage","When your data structures include timestamp columns or date fields","You should always choose a time-series database for all applications"),0,"TSDB: not for user profiles, orders, or relational data. Use PostgreSQL for general-purpose, TSDB for metrics."),
    ))
